@use '../../styles/tokens' as *;

.search-bar {
  display: flex;
  align-items: center;
  height: $search-bar-height;
  padding: 0 $space-4;
  border-bottom: 1px solid $border-100;
  gap: $space-3;
}

.search-bar__icon {
  flex-shrink: 0;
  color: $text-400;
}

.search-bar__breadcrumbs {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: $space-half;
}

.search-bar__breadcrumb {
  display: inline-flex;
  align-items: center;
  padding: $space-half $space-2;
  border: none;
  border-radius: $radius-sm;
  background: $color-surface-hover;
  font-family: $font-family;
  font-size: $font-sm;
  color: $text-600;
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $border-100;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -1px;
  }

  &--current {
    cursor: default;

    &:hover {
      background: $color-surface-hover;
    }
  }
}

.search-bar__breadcrumb-chevron {
  flex-shrink: 0;
  color: $text-400;
}

.search-bar__input {
  flex: 1;
  min-width: 0;
  height: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-family: $font-family;
  font-size: $font-search;
  color: $color-text-primary;
  caret-color: $color-accent;

  &::placeholder {
    color: $text-400;
  }
}

