141→  name: string;
142→  keyword: string;
143→  snippet: string;
144→  category: string;
145→  isShared: boolean;
146→  expiresAt: string;
147→}
148→
149→const INITIAL_SNIPPET_FORM: SnippetFormState = {
150→  name: '',
151→  keyword: '',
152→  snippet: '',
153→  category: 'general',
154→  isShared: false,
155→  expiresAt: '',
156→};
157→
158→const SNIPPET_CATEGORIES = [
159→  {
160→    label: 'General',
161→    value: 'general',
162→  },
163→  {
164→    label: 'Code',
165→    value: 'code',
166→  },
167→  {
168→    label: 'Email',
169→    value: 'email',
170→  },
171→  {
172→    label: 'Template',
173→    value: 'template',
174→  },
175→];
176→
177→interface CreateSnippetViewProps {
178→  onSubmit: (form: SnippetFormState) => void;
179→}
180→
181→function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
182→  const [snippetForm, setSnippetForm] =
183→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
184→  const [formErrors, setFormErrors] = useState<
185→    Partial<Record<keyof SnippetFormState, string>>
186→  >({});
187→
188→  const handleSubmit = useCallback(() => {
189→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
190→    if (!snippetForm.name.trim()) {
191→      errors.name = 'Name is required';
192→    }
193→    if (!snippetForm.snippet.trim()) {
194→      errors.snippet = 'Snippet content is required';
195→    }
196→    setFormErrors(errors);
197→    if (Object.keys(errors).length > 0) {
