199→    }
200→    onSubmit(snippetForm);
201→  }, [
202→    snippetForm,
203→    onSubmit,
204→  ]);
205→
206→  useEffect(() => {
207→    function handleKeyDown(e: KeyboardEvent) {
208→      if (e.key === 'Enter' && e.metaKey) {
209→        e.preventDefault();
210→        handleSubmit();
211→      }
212→    }
213→    window.addEventListener('keydown', handleKeyDown);
214→    return () => window.removeEventListener('keydown', handleKeyDown);
215→  }, [handleSubmit]);
216→
217→  return (
218→    <Form onSubmit={handleSubmit}>
219→      <FormTextField
220→        label="Name"
221→        value={snippetForm.name}
222→        onChange={v =>
223→          setSnippetForm(prev => ({
224→            ...prev,
225→            name: v,
226→          }))
227→        }
228→        placeholder="e.g. Email Signature"
229→        error={formErrors.name}
230→        autoFocus
231→      />
232→      <FormTextField
233→        label="Keyword"
234→        value={snippetForm.keyword}
235→        onChange={v =>
236→          setSnippetForm(prev => ({
237→            ...prev,
238→            keyword: v,
239→          }))
240→        }
241→        placeholder="e.g. !sig"
242→        description="Type this to expand the snippet"
243→      />
244→      <FormDropdown
245→        label="Category"
246→        value={snippetForm.category}
247→        onChange={v =>
248→          setSnippetForm(prev => ({
249→            ...prev,
250→            category: v,
251→          }))
252→        }
253→        options={SNIPPET_CATEGORIES}
254→        placeholder="Select a category"
255→      />
256→      <FormTextArea
257→        label="Snippet"
258→        value={snippetForm.snippet}
259→        onChange={v =>
260→          setSnippetForm(prev => ({
261→            ...prev,
262→            snippet: v,
263→          }))
264→        }
265→        placeholder="Enter your snippet content..."
266→        error={formErrors.snippet}
267→        rows={5}
268→      />
269→      <FormCheckbox
270→        label="Share with team"
271→        checked={snippetForm.isShared}
272→        onChange={v =>
273→          setSnippetForm(prev => ({
274→            ...prev,
275→            isShared: v,
276→          }))
277→        }
278→        description="Make this snippet available to your team members"
279→      />
280→      <FormDatePicker
281→        label="Expires"
282→        value={snippetForm.expiresAt}
283→        onChange={v =>
284→          setSnippetForm(prev => ({
285→            ...prev,
286→            expiresAt: v,
287→          }))
288→        }
289→        description="Optional expiration date"
290→      />
291→    </Form>
292→  );
293→}
