372→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
373→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
374→  const filteredColors = useMemo(
375→    () => filterColors(MOCK_COLORS, query),
