file.content:
@use '../../styles/tokens' as *;

.search-dropdown {
  position: relative;
  flex-shrink: 0;
}

.search-dropdown__trigger {
  display: flex;
  align-items: center;
  gap: $space-1;
  padding: $space-1 $space-2;
  border: none;
  border-radius: $radius-kbd;
  background: $text-100;
  font-family: $font-family;
  font-size: $font-sm;
  color: $text-600;
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;
  line-height: 1;
  height: 24px;

  &:hover {
    background: $border-200;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -1px;
  }
}

.search-dropdown__trigger-label {
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
}

.search-dropdown__trigger-chevron {
  flex-shrink: 0;
  transition: transform $transition-fast ease;

  &--open {
    transform: rotate(180deg);
  }
}

.search-dropdown__menu {
  position: absolute;
  top: calc(100% + $space-2);
  right: 0;
  min-width: 180px;
  max-height: 240px;
  overflow: hidden;
  background-color: $color-surface;
  border: 1px solid $border-100;
  border-radius: $radius-lg;
  box-shadow: $shadow-popover;
  z-index: 110;
  animation: search-dropdown-appear $transition-normal ease-out both;
}

.search-dropdown__menu-content {
  padding: $space-1;
  overflow-y: auto;
  max-height: 236px;
}

.search-dropdown__separator {
  height: 1px;
  margin: $space-1 $space-2;
  background-color: $border-100;
}

.search-dropdown__section-title {
  padding: $space-1 + $space-half $space-3;
  font-family: $font-family;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  color: $text-400;
  line-height: 1;
  white-space: nowrap;
  user-select: none;
}

.search-dropdown__option {
  display: flex;
  align-items: center;
  gap: $space-2;
  width: 100%;
  padding: $space-2 $space-3;
  background: none;
  border: none;
  border-radius: $radius-md;
  cursor: pointer;
  color: $color-text-primary;
  font-family: $font-family;
  font-size: $font-sm;
  line-height: 1;
  text-align: left;
  transition: background-color $transition-fast ease;

  &:hover,
  &--active {
    background-color: $color-accent;
    color: $color-text-on-accent;

    .search-dropdown__check {
      color: $color-text-on-accent;
    }
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -2px;
    border-radius: $radius-md;
  }
}

.search-dropdown__option-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

.search-dropdown__option-label {
  flex: 1;
  white-space: nowrap;
}

.search-dropdown__check {
  flex-shrink: 0;
  color: $color-accent;
}

@keyframes search-dropdown-appear {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(-4px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

