$color-text-on-accent: #ffffff;
$color-text-on-accent-secondary: rgba(255, 255, 255, 0.7);
$color-kbd-background-on-accent: rgba(255, 255, 255, 0.15);
$color-selection-background: rgba($color-accent, 0.1);
$color-code-background: rgba(255, 255, 255, 0.06);
$color-tag-background: rgba(255, 255, 255, 0.1);

$text-100: rgba($color-text-primary, 0.1);
$text-400: rgba($color-text-primary, 0.4);
$text-600: rgba($color-text-primary, 0.6);
$border-100: rgba($color-text-primary, 0.1);
$border-200: rgba($color-text-primary, 0.2);

$font-family-mono: 'SF Mono', SFMono-Regular, ui-monospace, Menlo, monospace;

$font-weight-regular: 400;
$font-weight-medium: 500;
$font-weight-semibold: 600;

$space-half: 2px;
$space-1: 4px;
$space-2: 8px;
$space-3: 12px;
$space-4: 16px;
$space-5: 20px;
$space-6: 24px;
$space-7: 28px;
$space-8: 32px;

$radius-sm: 4px;
$radius-md: 8px;
$radius-lg: 12px;
$radius-xl: 16px;
$radius-kbd: 6px;
$radius-list-item: 10px;
$radius-window: 18px;

$shadow-window:
  0 24px 80px rgba(0, 0, 0, 0.55),
  0 2px 12px rgba(0, 0, 0, 0.35);
$shadow-popover:
  0 12px 32px rgba(0, 0, 0, 0.45),
  0 1px 6px rgba(0, 0, 0, 0.25);

$font-family:
  'Inter',
  -apple-system,
  BlinkMacSystemFont,
  'SF Pro Text',
  'Segoe UI',
  Roboto,
  Helvetica,
  Arial,
  sans-serif;

$font-xs: 11px;
$font-sm: 12px;
$font-md: 13px;
$font-base: 14px;
$font-lg: 15px;
$font-search: 16px;
$font-xl: 20px;

$command-palette-width: 750px;
$alert-dialog-width: 260px;
$backdrop-blur: 4px;
$backdrop-overlay: rgba(0, 0, 0, 0.4);
$search-bar-height: 56px;
$list-item-height: 40px;
$action-panel-height: 40px;
$size-grid-icon: 64px;

$transition-fast: 80ms;
$transition-normal: 150ms;
$transition-slow: 250ms;

@use '../../styles/tokens' as *;

.search-dropdown {
  position: relative;
  flex-shrink: 0;
}

.search-dropdown__trigger {
  display: flex;
  align-items: center;
  gap: $space-1;
  padding: $space-1 $space-2;
  border: none;
  border-radius: $radius-kbd;
  background: $text-100;
  font-family: $font-family;
  font-size: $font-sm;
  color: $text-600;
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;
  line-height: 1;
  height: 24px;

  &:hover {
    background: $border-200;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -1px;
  }
}

.search-dropdown__trigger-label {
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
}

.search-dropdown__trigger-chevron {
  flex-shrink: 0;
  transition: transform $transition-fast ease;

  &--open {
    transform: rotate(180deg);
  }
}

.search-dropdown__menu {
  position: absolute;
  top: calc(100% + $space-2);
  right: 0;
  min-width: 180px;
  max-height: 240px;
  overflow: hidden;
  background-color: $color-surface;
  border: 1px solid $border-100;
  border-radius: $radius-lg;
  box-shadow: $shadow-popover;
  z-index: 110;
  animation: search-dropdown-appear $transition-normal ease-out both;
}

.search-dropdown__menu-content {
  padding: $space-1;
  overflow-y: auto;
  max-height: 236px;
}

.search-dropdown__separator {
  height: 1px;
  margin: $space-1 $space-2;
  background-color: $border-100;
}

.search-dropdown__section-title {
  padding: $space-1 + $space-half $space-3;
  font-family: $font-family;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  color: $text-400;
  line-height: 1;
  white-space: nowrap;
  user-select: none;
}

.search-dropdown__option {
  display: flex;
  align-items: center;
  gap: $space-2;
  width: 100%;
  padding: $space-2 $space-3;
  background: none;
  border: none;
  border-radius: $radius-md;
  cursor: pointer;
  color: $color-text-primary;
  font-family: $font-family;
  font-size: $font-sm;
  line-height: 1;
  text-align: left;
  transition: background-color $transition-fast ease;

  &:hover,
  &--active {
    background-color: $color-accent;
    color: $color-text-on-accent;

    .search-dropdown__check {
      color: $color-text-on-accent;
    }
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -2px;
    border-radius: $radius-md;
  }
}

.search-dropdown__option-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

.search-dropdown__option-label {
  flex: 1;
  white-space: nowrap;
}

.search-dropdown__check {
  flex-shrink: 0;
  color: $color-accent;
}

@keyframes search-dropdown-appear {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(-4px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

